const express = require('express');
const session = require('express-session');
const jwt = require('jsonwebtoken');
const axios = require('axios');

const app = express();
const port = 3000;

// Configure session middleware
app.use(session({
  secret: 'your-secret-key',
  resave: false,
  saveUninitialized: true,
  cookie: { secure: false } // Set to true if using HTTPS
}));

// OpenID Connect configuration
const oidcConfig = {
  clientId: 'your-client-id',
  clientSecret: 'your-client-secret',
  redirectUri: 'http://localhost:3000/callback',
  authorizationEndpoint: 'https://your-oidc-provider.com/auth',
  tokenEndpoint: 'https://your-oidc-provider.com/token',
  userInfoEndpoint: 'https://your-oidc-provider.com/userinfo'
};

// Redirect to OpenID Connect provider for authentication
app.get('/login', (req, res) => {
  const authUrl = `${oidcConfig.authorizationEndpoint}?response_type=code&client_id=${oidcConfig.clientId}&redirect_uri=${oidcConfig.redirectUri}&scope=openid profile email`;
  res.redirect(authUrl);
});

// Handle callback from OpenID Connect provider
app.get('/callback', async (req, res) => {
  const code = req.query.code;
  try {
    const response = await axios.post(oidcConfig.tokenEndpoint, null, {
      params: {
        grant_type: 'authorization_code',
        code: code,
        redirect_uri: oidcConfig.redirectUri,
        client_id: oidcConfig.clientId,
        client_secret: oidcConfig.clientSecret
      }
    });

    const idToken = response.data.id_token;
    const decodedToken = jwt.decode(idToken);

    // Create user session with claims
    req.session.user = {
      id: decodedToken.sub,
      name: decodedToken.name,
      email: decodedToken.email
    };

    res.redirect('/profile');
  } catch (error) {
    res.status(500).send('Authentication failed');
  }
});

// User profile route
app.get('/profile', (req, res) => {
  if (!req.session.user) {
    return res.redirect('/login');
  }
  res.send(`Hello, ${req.session.user.name}`);
});

app.listen(port, () => {
  console.log(`App listening at http://localhost:${port}`);
});